import java.util.Arrays;

public static long solve(long[] piles) {
    Arrays.sort(piles);
    int n = piles.length;
    int k = n / 3;
    long sum = 0;
    for (int i = 0; i < k; i++) {
        sum += piles[n - 2 * (i + 1)];
    }
    return sum;
}
